import { AgentClient } from '@azure/ai-projects';
import { VexClient } from 'vex-sdk';

// npm install @azure/ai-projects vex-sdk
const vex = new VexClient({ apiKey: 'vex_123', tenantId: 'azure-tenant-uuid' });
const agent = new AgentClient({ projectName: 'enterprise-saas-agent' });

async function validateAgentStream(req: Request, res: Response) {
  const stream = await agent.createThreadStream(req.body);

  res.setHeader('Content-Type', 'text/plain');

  for await (const event of stream) {
    if (event.type === 'tool_call' && event.tool === 'bing_search') {
      const validation = await vex.validateGroundingData(
        event.result,
        { policies: ['data_residency', 'freshness_24h'], tenantZone: 'eu-west-1' }
      );

      if (!validation.passed) {
        res.write('[POLICY_BLOCK] Grounding data rejected\n');
        continue;
      }
    }

    if (event.type === 'file_search') {
      // Strip Azure metadata
      event.content = vex.sanitizeFileContent(event.content);
    }

    res.write(JSON.stringify(event) + '\n');
  }
}
